// Additional helper function to parse expressions
expr_parser = (expr, context) => {
    switch (context.currentToken.type) {
        case "logic_expr":
            return logic_expr(context);
        case "comp_expr":
            return comp_expr(context);
        case "math_expr":
            return math_expr(context);
        case "term":
            return term(context);
        default:
            throw new Error(`Unexpected token ${context.currentToken.type}`);
    }
}

// Additional helper function to parse logical expressions
logic_expr = (context) => {
    let left = expr_parser(context);
    while (context.currentToken.value === "||" || context.currentToken.value === "&&") {
        let op = context.currentToken.value;
        context.nextToken();
        let right = expr_parser(context);
        left = { type: "binary", operator: op, left: left, right: right };
    }
    return left;
}

// Additional helper function to parse comparison expressions
comp_expr = (context) => {
    let left = expr_parser(context);
    while (context.currentToken.value === "==" || context.currentToken.value === ">" || context.currentToken.value === "<" || context.currentToken.value === "!=" || context.currentToken.value === "<=" || context.currentToken.value === ">=") {
        let op = context.currentToken.value;
        context.nextToken();
        let right = expr_parser(context);
        left = { type: "binary", operator: op, left: left, right: right };
    }
    return left;
}

// Additional helper function to parse mathematical expressions
math_expr = (context) => {
    let left = expr_parser(context);
    while (context.currentToken.value === "+" || context.currentToken.value === "-" || context.currentToken.value === "*" || context.currentToken.value === "/" || context.currentToken.value === "mod") {
        let op = context.currentToken.value;
        context.nextToken();
        let right = expr_parser(context);
        left = { type: "binary", operator: op, left: left, right: right };
    }
    return left;
}

// Additional helper function to parse terms
term = (context) => {
    if (context.currentToken.type === "IDENT") {
        let ident = context.currentToken.value;
        context.nextToken();
        return { type: "identifier", value: ident };
    } else if (context.currentToken.type === "int_lit") {
        let lit = parseInt(context.currentToken.value);
        context.nextToken();
        return { type: "integer", value: lit };
    } else {
        throw new Error(`Unexpected token ${context.currentToken.type}`);
    }
}

