```python
import re

class Model:
    def __init__(self, var_decls, constraints, solve, output_opt):
        self.var_decls = var_decls
        self.constraints = constraints
        self.solve = solve
        self.output_opt = output_opt

class VarDecl:
    def __init__(self, name, type):
        self.name = name
        self.type = type

class Constraint:
    def __init__(self, expression):
        self.expression = expression

class Expr:
    def __init__(self, value):
        self.value = value

class LogicExpr:
    def __init__(self, left, op, right):
        self.left = left
        self.op = op
        self.right = right

class CompExpr:
    def __init__(self, left, op, right):
        self.left = left
        self.op = op
        self.right = right

class MathExpr:
    def __init__(self, left, op, right):
        self.left = left
        self.op = op
        self.right = right

class Term:
    def __init__(self, value):
        self.value = value

class Type:
    def __init__(self, name):
        self.name = name

class IntLit:
    def __init__(self, value):
        self.value = value

def parse_user_intent(user_input):
    # Split the input into lines
    lines = user_input.split('\n')

    # Parse each line according to the EBNF grammar
    start = parse_start(lines)
    return start

def parse_start(lines):
    if len(lines) < 1:
        raise ValueError("Invalid input: Start rule requires at least one line")

    # Parse the first line as the model
    model = parse_model(lines[0])

    # Parse remaining lines as constraints, solve, and output options
    constraints = []
    solve = None
    output_opt = ''
    for line in lines[1:]:
        if line.strip().startswith('constraint'):
            constraints.append(parse_constraint(line))
        elif line.strip() == 'solve satisfy':
            solve = 'satisfy'
        elif line.strip() == 'solve maximize IDENT':
            solve = f'maximize {line.split()[2]}'
        elif line.strip() == 'solve minimize IDENT':
            solve = f'minimize {line.split()[2]}'
        elif line.strip().startswith('output [show('):
            match = re.search(r'show\((.*?)\)', line)
            if match:
                output_opt = f'output [{match.group(1)}]'
            else:
                raise ValueError(f"Invalid output option: {line}")

    return Model(model, constraints, solve, output_opt)

def parse_model(line):
    # Split the line into parts
    parts = line.split()

    if len(parts) != 4 or parts[0] != 'var':
        raise ValueError("Invalid model declaration: Expected 'var'")

    name = parts[1]
    type = parts[2]

    if parts[3] != ':':
        raise ValueError("Invalid model declaration: Expected ':'")

    var_name = parts[4].strip()

    if not re.match(r'[a-zA-Z_][a-zA-Z0-9_]*', var_name):
        raise ValueError(f"Invalid variable name: {var_name}")

    return VarDecl(var_name, Type(type))

def parse_constraint(line):
    # Split the line into parts
    parts = line.split()

    if len(parts) != 3 or parts[0] != 'constraint':
        raise ValueError("Invalid constraint declaration: Expected 'constraint'")

    expression = parse_expr(parts[2])

    return Constraint(expression)

def parse_expr(line):
    # Split the line into parts
    parts = line.split()

    if len(parts) == 1:
        return Expr(int(parts[0]))

    if parts[1] == '+':
        return MathExpr(parse_term(parts[0]), '+', parse_term(parts[2]))
    elif parts[1] == '-':
        return MathExpr(parse_term(parts[0]), '-', parse_term(parts[2]))
    elif parts[1] == '*':
        return MathExpr(parse_term(parts[0]), '*', parse_term(parts[2]))
    elif parts[1] == '/':
        return MathExpr(parse_term(parts[0]), '/', parse_term(parts[2]))
    elif parts[1] == 'mod':
        return MathExpr(parse_term(parts[0]), '%', parse_term(parts[2]))

    if parts[1] == '==':
        return CompExpr(parse_term(parts[0]), '==', parse_term(parts[2]))
    elif parts[1] == '>':
        return CompExpr(parse_term(parts[0]), '>', parse_term(parts[2]))
    elif parts[1] == '<':
        return CompExpr(parse_term(parts[0]), '<', parse_term(parts[2]))
    elif parts[1] == '!=':
        return CompExpr(parse_term(parts[0]), '!=', parse_term(parts[2]))
    elif parts[1] == '<=':
        return CompExpr(parse_term(parts[0]), '<=', parse_term(parts[2]))
    elif parts[1] == '>=':
        return CompExpr(parse_term(parts[0]), '>=', parse_term(parts[2]))
    elif parts[1] == 'in':
        return CompExpr(parse_term(parts[0]), 'in', parse_term(parts[2]))

    raise ValueError("Invalid expression")

def parse_term(line):
    # Split the line into parts
    parts = line.split()

    if len(parts) == 1:
        return Expr(int(parts[0]))

    return Term(parts[0])

