    # Parse each line
    for line in lines:
        line = line.strip()

        if line.startswith('var'):
            parse_var_declaration(line)
        elif line.startswith('constraint'):
            parse_constraint(line)
        elif line.startswith('solve'):
            parse_solve_statement(line)
        elif line.startswith('output'):
            parse_output_option(line)

# Function to parse a variable declaration
def parse_var_declaration(line):
    parts = line.split()
    if len(parts) < 4:
        raise ValueError("Invalid var declaration")
    var_type = parts[1]
    var_name = parts[3]
    if var_type not in types:
        raise ValueError(f"Unknown type {var_type}")
    if var_name in variables:
        raise ValueError(f"Variable {var_name} already exists")
    variables[var_name] = (var_type, None)

# Function to parse a constraint
def parse_constraint(line):
    parts = line.split()
    if len(parts) < 3:
        raise ValueError("Invalid constraint")
    expr = parse_expression(parts[2])
    constraints.append((expr, None))

# Function to parse an expression
def parse_expression(expr):
    if expr.startswith('sum'):
        return parse_sum_expr(expr)
    else:
        return parse_comp_expr(expr)

# Function to parse a sum expression
def parse_sum_expr(expr):
    parts = expr.split('(')
    if len(parts) != 2:
        raise ValueError("Invalid sum expression")
    ident = parts[0].strip()
    if ident not in variables:
        raise ValueError(f"Undefined variable {ident}")
    term = variables[ident][1]
    if term is None:
        term = variables[ident][1] = parse_term(parts[1][:-1])
    return term

# Function to parse a term
def parse_term(term):
    if term.isdigit():
        return int(term)
    else:
        return term

# Function to parse a comparison expression
def parse_comp_expr(expr):
    parts = expr.split()
    if len(parts) < 4:
        raise ValueError("Invalid comparison expression")
    left = parse_expression(parts[0])
    op = parts[1]
    right = parse_expression(parts[2])
    if op not in comp_ops:
        raise ValueError(f"Unknown comparison operator {op}")
    return (left, op, right)

# Function to parse a solve statement
def parse_solve_statement(line):
    parts = line.split()
    if len(parts) < 3:
        raise ValueError("Invalid solve statement")
    if parts[1] not in solves:
        solves.append(parts[1])

# Function to parse an output option
def parse_output_option(line):
    parts = line.split()
    if len(parts) < 3:
        raise ValueError("Invalid output option")
    if parts[1] not in outputs:
        outputs.append(parts[1])

# Example usage
input_str = """
var int: y;
constraint y == 10;
solve satisfy;
output [show(y)];
"""
parse_input(input_str)
print(variables)
print(constraints)
print(expressions)
print(solves)
print(outputs)
```

